from prefect import task, flow
from prefect.tasks import task_input_hash
from datetime import timedelta

@task(
    retries=3,
    retry_delay_seconds=60,          # Fixed delay
    # retry_delay_seconds=[30, 60, 120]  # Custom per-attempt delays
    cache_key_fn=task_input_hash,    # Don't re-run if input unchanged
    cache_expiration=timedelta(hours=1),
)
def fetch_api_data(url: str) -> dict:
    import httpx
    response = httpx.get(url, timeout=10)
    response.raise_for_status()
    return response.json()

@flow
def data_pipeline():
    data = fetch_api_data("https://api.example.com/records")
    return data

from datetime import date, timedelta
from concurrent.futures import ThreadPoolExecutor, as_completed
import logging

logger = logging.getLogger(__name__)

def run_pipeline_for_date(logical_date: date) -> bool:
    """Run the pipeline for a single logical date. Returns True on success."""
    try:
        records = extract_data(logical_date)
        transformed = transform(records)
        load_to_warehouse(transformed, logical_date)
        logger.info(f"SUCCESS: {logical_date}")
        return True
    except Exception as e:
        logger.error(f"FAILED: {logical_date} — {e}")
        return False

def backfill(start: date, end: date, max_workers: int = 4):
    dates = []
    current = start
    while current <= end:
        dates.append(current)
        current += timedelta(days=1)

    failed = []
    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        futures = {executor.submit(run_pipeline_for_date, d): d for d in dates}
        for future in as_completed(futures):
            d = futures[future]
            if not future.result():
                failed.append(d)

    if failed:
        logger.error(f"Backfill complete. Failed dates: {failed}")
    else:
        logger.info("Backfill complete. All dates succeeded.")

if __name__ == "__main__":
    backfill(
        start=date(2024, 1, 1),
        end=date(2024, 1, 31),
        max_workers=4,
    )

def run_with_state_tracking(logical_date: date, conn):
    conn.execute(
        "UPDATE backfill_state SET status='running', started_at=NOW() WHERE logical_date=%s",
        (logical_date,)
    )
    try:
        run_pipeline_for_date(logical_date)
        conn.execute(
            "UPDATE backfill_state SET status='success', completed_at=NOW() WHERE logical_date=%s",
            (logical_date,)
        )
    except Exception as e:
        conn.execute(
            "UPDATE backfill_state SET status='failed', error_msg=%s WHERE logical_date=%s",
            (str(e), logical_date)
        )
        raise

from dagster import asset, DailyPartitionsDefinition

@asset(
    partitions_def=DailyPartitionsDefinition(start_date="2024-01-01"),
)
def daily_events(context):
    partition_date = context.partition_key  # e.g., "2024-01-15"
    # Use partition_date, never datetime.now()
    return fetch_events(date=partition_date)
